sql:
SELECT COUNT(*) AS num_arrests_in_2018
FROM arrests
WHERE arrest_year = 2018 AND arrest_outcome = 'Charged';

SELECT officer_id 
FROM officers 
WHERE rank = 'Detective' AND years_of_service > 5;

SELECT COUNT(*)
FROM arrests
INNER JOIN persons ON arrests.person_id = persons.person_id;

SELECT (
    SELECT COUNT(*)
    FROM arrests
    WHERE booked = 1 AND arrest_outcome = 'released'
) * 100.0 /
(
    SELECT COUNT(*)
    FROM arrests
) AS percentage;
